def process_order(order):
    subtotal = calculate_subtotal(order)
    discount = calculate_discount(subtotal, order["customer_type"])
    shipping = calculate_shipping(subtotal)
    tax = calculate_tax(subtotal, discount)
    total = calculate_total(subtotal, discount, shipping, tax)

    summary = {
        "customer": order["customer_name"],
        "subtotal": subtotal,
        "discount": discount,
        "shipping": shipping,
        "tax": tax,
        "total": total,
    }
    return summary

def calculate_subtotal(order):
    subtotal = 0
    for item in order["items"]:
        subtotal += item["price"] * item["quantity"]
    return subtotal

def calculate_discount(subtotal, customer_type):
    discount = 0
    if customer_type == "vip":
        discount = subtotal * 0.10
    elif customer_type == "member":
        discount = subtotal * 0.05
    return discount

def calculate_shipping(subtotal):
    shipping = 0 if subtotal > 100 else 12
    return shipping

def calculate_tax(subtotal, discount):
    tax = (subtotal - discount) * 0.08
    return tax

def calculate_total(subtotal, discount, shipping, tax):
    total = subtotal - discount + shipping + tax
    return total
